+// ─── Exhaustive DevTools Logging ─────────────────────────────────
+// Every real WASM operation is logged to browser console for full transparency.
+const LOG_PREFIX = '%c[asupersync-wasm]';
+const LOG_STYLE = 'color:#3B82F6;font-weight:bold;';
+const LOG_OK    = 'color:#22C55E;';
+const LOG_ERR   = 'color:#EF4444;';
+const LOG_WARN  = 'color:#F97316;';
+
+function logWasm(op, args, result) {
+  const outcome = result?.outcome || 'void';
+  const style = outcome === 'ok' ? LOG_OK : outcome === 'err' ? LOG_ERR : LOG_WARN;
+  const slot = result?.value?.slot !== undefined ? ` → slot=${result.value.slot} gen=${result.value.generation}` : '';
+  const detail = result?.failure ? ` [${result.failure.code}: ${result.failure.message}]` : '';
+  console.log(
+    `${LOG_PREFIX} %c${op}%c(${JSON.stringify(args).slice(0,120)}) %c→ ${outcome}${slot}${detail}`,
+    LOG_STYLE, 'color:#06B6D4;font-weight:600;', 'color:#94A3B8;', style
+  );
+  if (outcome === 'ok' && result?.value && typeof result.value === 'object') {
+    console.log(`${LOG_PREFIX} %c  handle:`, LOG_STYLE, 'color:#64748B;', result.value.toJSON ? result.value.toJSON() : result.value);
+  }
+}
